}

static void write_case(FILE *fp, const SolveResult *res, int last) {
    fprintf(fp, "    {\n      \"name\": ");
    esc(fp, res->name);
    fprintf(fp, ",\n      \"ok\": %s,\n", res->ok ? "true" : "false");
    fprintf(fp, "      \"iterations\": %d,\n", res->iterations);
    fprintf(fp, "      \"final_residual\": %.17g,\n", res->final_residual);
