    fprintf(fp, "      \"hit_limit\": %s\n    }", res->hit_limit ? "true" : "false");
    if (!last) {
        fprintf(fp, ",");
    }
    fprintf(fp, "\n");
}

int emit_t(const SolveResult *res, const char *audit_path) {
